import{c as s,cG as i,cb as t,c8 as a,cf as e,cT as d,ce as l}from"./chunks/framework.BlkIsu1j.js";const n=JSON.parse('{"title":"20. 特权级别与 CSR","description":"","frontmatter":{"title":"20. 特权级别与 CSR","outline":"deep","layout":"doc","prev":{"text":"19. 综合实战：交互式计算器","link":"/lang/assembly/19_calculator_project"},"next":{"text":"21. 异常与中断","link":"/lang/assembly/21_exceptions_interrupts"},"sidebar":true,"date":"2026-05-31T10:00:00.000Z"},"headers":[],"relativePath":"lang/assembly/20_privilege_csr.md","filePath":"lang/assembly/20_privilege_csr.md","lastUpdated":1780203085000}'),h={id:"frontmatter-title",tabindex:"-1"};const r=s({name:"lang/assembly/20_privilege_csr.md"},[["render",function(s,n,r,c,p,k){return i(),t("div",null,[a("h1",h,[e(d(s.$frontmatter.title)+" ",1),n[0]||(n[0]=a("a",{class:"header-anchor",href:"#frontmatter-title","aria-label":"Permalink to “{{ $frontmatter.title }}”"},"​",-1))]),n[1]||(n[1]=l('<p>前 19 章我们一直在用户态（User mode）写汇编——调用 <code>ecall</code> 请求操作系统代劳 I/O、退出等操作。但你有没有想过：<code>ecall</code> 之后发生了什么？操作系统内核如何获得 CPU 控制权？定时器中断又是怎样让 OS 抢占当前进程的？这些问题的答案藏在 RISC-V 特权架构中。本章讲解三种特权模式以及 CSR（Control and Status Register）体系——它们是理解操作系统、异常处理和虚拟内存的基础。</p><h2 id="三种特权模式" tabindex="-1">三种特权模式 <a class="header-anchor" href="#三种特权模式" aria-label="Permalink to “三种特权模式”">​</a></h2><h3 id="模式层级" tabindex="-1">模式层级 <a class="header-anchor" href="#模式层级" aria-label="Permalink to “模式层级”">​</a></h3><p>RISC-V 定义了三种特权级别（privilege level），从高到低分别为：</p><table tabindex="0"><thead><tr><th>级别</th><th>缩写</th><th>典型职责</th><th>示例代码</th></tr></thead><tbody><tr><td>Machine</td><td>M</td><td>固件、bootloader、安全监控</td><td>OpenSBI、U-Boot SPL</td></tr><tr><td>Supervisor</td><td>S</td><td>操作系统内核</td><td>Linux 内核、xv6</td></tr><tr><td>User</td><td>U</td><td>用户应用程序</td><td>你的汇编程序、浏览器</td></tr></tbody></table><p>层级关系是严格的：<strong>高特权级可以访问低特权级的所有资源，反之不行</strong>。M 模式拥有对硬件的完全控制权——这是 RISC-V 设计中的一个关键决策：即使在最复杂的系统中，总有一个&quot;最高权威&quot;可以处理任何硬件事件。</p><h3 id="嵌入式简化-仅-m-模式" tabindex="-1">嵌入式简化：仅 M 模式 <a class="header-anchor" href="#嵌入式简化-仅-m-模式" aria-label="Permalink to “嵌入式简化：仅 M 模式”">​</a></h3><p>RISC-V 的模块化哲学同样适用于特权架构。对于没有操作系统的嵌入式系统（bare-metal），处理器可以<strong>只实现 M 模式</strong>——所有代码都在最高特权下运行，无需模式切换：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span># 嵌入式 bare-metal 程序的典型启动</span></span>\n<span class="line"><span>    .section .text.init</span></span>\n<span class="line"><span>    .globl _start</span></span>\n<span class="line"><span>_start:</span></span>\n<span class="line"><span>    la   sp, _stack_top       # 设置栈指针</span></span>\n<span class="line"><span>    j    main                  # 直接跳转到 C main()</span></span></code></pre></div><p>这种场景下，CSR 访问和异常处理仍然可用——M 模式并不要求 S/U 模式存在。</p><h3 id="模式切换机制" tabindex="-1">模式切换机制 <a class="header-anchor" href="#模式切换机制" aria-label="Permalink to “模式切换机制”">​</a></h3><p>从低特权向高特权切换只有一条路：</p><div class="language-asm"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">ecall   </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # U → S（操作系统调用）或 U → M（bare-metal 系统调用）</span></span></code></pre></div><p><code>ecall</code> 指令触发环境调用异常（Environment Call），硬件自动将当前 PC 保存到 <code>mepc</code>/<code>sepc</code>，将原因码写入 <code>mcause</code>/<code>scause</code>，然后跳转到陷阱处理程序。从操作系统视角看，用户程序的 <code>ecall</code> 就是&quot;敲门&quot;——&quot;请 OS 代我执行特权操作&quot;。</p><p>从高特权向低特权返回：</p><div class="language-asm"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">mret   </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # M → 返回原特权级（可能是 S 或 U）</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">sret   </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # S → 返回原特权级（通常是 U）</span></span></code></pre></div><p><code>mret</code>/<code>sret</code> 完成三件事：</p><ol><li>从 <code>mepc</code>/<code>sepc</code> 恢复 PC</li><li>从 <code>mstatus.MPP</code>/<code>sstatus.SPP</code> 恢复特权级别</li><li>从 <code>mstatus.MPIE</code>/<code>sstatus.SPIE</code> 恢复中断使能</li></ol><p>这意味着<strong>进入陷阱时硬件自动保存上下文到 CSR，返回时从 CSR 自动恢复</strong>——设计得非常规整。</p><h3 id="权限检查" tabindex="-1">权限检查 <a class="header-anchor" href="#权限检查" aria-label="Permalink to “权限检查”">​</a></h3><p>当处理器在 U 模式下尝试访问 M 模式 CSR 时，会触发非法指令异常。这是硬件级别的隔离——用户态程序无法绕过 OS 直接操作硬件。</p><h2 id="csr-控制与状态寄存器" tabindex="-1">CSR：控制与状态寄存器 <a class="header-anchor" href="#csr-控制与状态寄存器" aria-label="Permalink to “CSR：控制与状态寄存器”">​</a></h2><h3 id="csr-是什么" tabindex="-1">CSR 是什么 <a class="header-anchor" href="#csr-是什么" aria-label="Permalink to “CSR 是什么”">​</a></h3><p>RISC-V 的通用寄存器（x0-x31）是 32 个——对大多数计算任务够用，但对系统控制远远不够。因此 RISC-V 设计了一个独立的 <strong>12 位地址空间</strong>（0x000-0xFFF，共 4096 个槽位）专门存放控制和状态寄存器——这就是 CSR（Control and Status Register）。</p><p>关键特性：</p><ul><li><strong>独立于通用寄存器</strong>：不是 x0-x31 的一部分，有自己的地址空间</li><li><strong>专用指令访问</strong>：不能 <code>add csr, x0, x0</code>——必须用 <code>csr*</code> 系列指令</li><li><strong>按特权级分配</strong>：低 12 位决定了 CSR 所属的特权级（bit[9:8]：00=U, 01=S, 10=HS, 11=M）</li></ul><h3 id="csr-指令一览" tabindex="-1">CSR 指令一览 <a class="header-anchor" href="#csr-指令一览" aria-label="Permalink to “CSR 指令一览”">​</a></h3><p>RISC-V 定义了六条 CSR 操作指令，分为寄存器源和立即数源两组：</p><table tabindex="0"><thead><tr><th>指令</th><th>语义</th><th>伪代码</th></tr></thead><tbody><tr><td><code>csrrw rd, csr, rs1</code></td><td>原子读-写</td><td><code>t = CSR; CSR = rs1; rd = t</code></td></tr><tr><td><code>csrrs rd, csr, rs1</code></td><td>原子读-置位</td><td><code>t = CSR; CSR = t | rs1; rd = t</code></td></tr><tr><td><code>csrrc rd, csr, rs1</code></td><td>原子读-清除</td><td><code>t = CSR; CSR = t &amp; ~rs1; rd = t</code></td></tr><tr><td><code>csrrwi rd, csr, imm</code></td><td>立即数读-写</td><td><code>t = CSR; CSR = imm; rd = t</code></td></tr><tr><td><code>csrrsi rd, csr, imm</code></td><td>立即数读-置位</td><td><code>t = CSR; CSR = t | imm; rd = t</code></td></tr><tr><td><code>csrrci rd, csr, imm</code></td><td>立即数读-清除</td><td><code>t = CSR; CSR = t &amp; ~imm; rd = t</code></td></tr></tbody></table><p>核心约定：</p><ul><li><strong>总是返回旧值</strong>：<code>rd</code> 始终获得 CSR 的旧值——这让你在修改后仍能知道之前的状态</li><li><strong>rs1=x0 时</strong>：对于 <code>csrrw</code>，若 <code>rs1=x0</code>，则不写入 CSR（读而不写）；对于 <code>csrrs</code>/<code>csrrc</code>，若 <code>rs1=x0</code>，则只读不改</li><li><strong>立即数范围</strong>：<code>imm</code> 是 5 位无符号数（0-31），由 <code>rs1</code> 字段编码</li></ul><p><code>csrrs</code>/<code>csrrc</code> 的&quot;读-置位&quot;和&quot;读-清除&quot;语义对中断使能管理特别有用——你可以原子地开启或关闭某个中断位，而不会干扰其他位。</p><h3 id="伪指令简化" tabindex="-1">伪指令简化 <a class="header-anchor" href="#伪指令简化" aria-label="Permalink to “伪指令简化”">​</a></h3><p>汇编器提供了几条常用伪指令（在基础指令章节也提过）：</p><div class="language-asm"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">csrr rd, csr         </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # → csrrs rd, csr, x0    纯读 CSR</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">csrw csr, rs1        </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # → csrrw x0, csr, rs1    纯写 CSR（丢弃旧值）</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">csrs csr, rs1        </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # → csrrs x0, csr, rs1    置位（不读旧值）</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">csrc csr, rs1        </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # → csrrc x0, csr, rs1    清除（不读旧值）</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">csrwi csr, imm       </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # → csrrwi x0, csr, imm   立即数纯写</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">csrsi csr, imm       </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # → csrrsi x0, csr, imm   立即数量位</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">csrci csr, imm       </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # → csrrci x0, csr, imm   立即数清除</span></span></code></pre></div><p>日常编码中几乎只用伪指令——<code>csrr t0, mhartid</code> 比 <code>csrrs t0, mhartid, x0</code> 清晰太多。</p><h2 id="常用-csr-分类详解" tabindex="-1">常用 CSR 分类详解 <a class="header-anchor" href="#常用-csr-分类详解" aria-label="Permalink to “常用 CSR 分类详解”">​</a></h2><h3 id="信息类——识别处理器" tabindex="-1">信息类——识别处理器 <a class="header-anchor" href="#信息类——识别处理器" aria-label="Permalink to “信息类——识别处理器”">​</a></h3><table tabindex="0"><thead><tr><th>CSR</th><th>地址</th><th>描述</th></tr></thead><tbody><tr><td><code>mvendorid</code></td><td>0xF11</td><td>制造商 ID（JEDEC 编码，0 表示未实现）</td></tr><tr><td><code>marchid</code></td><td>0xF12</td><td>微架构 ID</td></tr><tr><td><code>mimpid</code></td><td>0xF13</td><td>实现版本号</td></tr><tr><td><code>mhartid</code></td><td>0xF14</td><td>硬件线程 ID（多核中区分 hart）</td></tr></tbody></table><p>这些是只读 CSR，提供处理器身份信息。多核 boot 流程中，每个 hart 通过读取 <code>mhartid</code> 判断自己是不是主核：</p><div class="language-asm"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">csrr    t0, mhartid          </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 读出当前 hart ID</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">bnez    t0, secondary_hart   </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # hart 0 是主核，其他 hart 进入等待</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 主核初始化代码...</span></span></code></pre></div><h3 id="计数器类——性能分析的核心" tabindex="-1">计数器类——性能分析的核心 <a class="header-anchor" href="#计数器类——性能分析的核心" aria-label="Permalink to “计数器类——性能分析的核心”">​</a></h3><p>RISC-V 规范定义了一组只读的 64 位计数器：</p><table tabindex="0"><thead><tr><th>CSR</th><th>地址</th><th>描述</th></tr></thead><tbody><tr><td><code>cycle</code></td><td>0xC00</td><td>自启动以来的 CPU 时钟周期计数</td></tr><tr><td><code>cycleh</code></td><td>0xC80</td><td><code>cycle</code> 的高 32 位（RV32）</td></tr><tr><td><code>time</code></td><td>0xC01</td><td>实时计数器（通常由 RTC 驱动）</td></tr><tr><td><code>timeh</code></td><td>0xC81</td><td><code>time</code> 的高 32 位（RV32）</td></tr><tr><td><code>instret</code></td><td>0xC02</td><td>已退役的指令计数</td></tr><tr><td><code>instreth</code></td><td>0xC82</td><td><code>instret</code> 的高 32 位（RV32）</td></tr></tbody></table><p>这三个计数器对性能分析至关重要：</p><div class="language-asm"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 测量一段代码的执行周期</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    csrr    t0, cycle         </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 起始周期</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # ... 被测代码段 ...</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    csrr    t1, cycle         </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 结束周期</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    sub</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">     t2, t1, t0        </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # t2 = 执行这段代码的周期数</span></span></code></pre></div><p>在 RV64 下，<code>csrr</code> 直接读出 64 位值。RV32 下需要分别读取低 32 位和高 32 位（读低 32 位时会冻结高 32 位快照，避免进位导致的不一致）。</p><h3 id="陷阱设置类——控制异常-中断的去向" tabindex="-1">陷阱设置类——控制异常/中断的去向 <a class="header-anchor" href="#陷阱设置类——控制异常-中断的去向" aria-label="Permalink to “陷阱设置类——控制异常/中断的去向”">​</a></h3><table tabindex="0"><thead><tr><th>CSR</th><th>地址</th><th>描述</th></tr></thead><tbody><tr><td><code>mtvec</code></td><td>0x305</td><td>陷阱向量基址寄存器（Trap Vector Base）</td></tr><tr><td><code>medeleg</code></td><td>0x302</td><td>异常委托寄存器（将异常委托给 S 模式处理）</td></tr><tr><td><code>mideleg</code></td><td>0x303</td><td>中断委托寄存器（将中断委托给 S 模式处理）</td></tr></tbody></table><p><code>mtvec</code> 是陷阱处理的入口——当异常或中断发生时，PC 跳转到 <code>mtvec</code> 指定的地址。它有 Direct 和 Vectored 两种模式（bit[0]=0 为 Direct，bit[0]=1 为 Vectored）。</p><p><code>medeleg</code>/<code>mideleg</code> 允许 M 模式将某些异常/中断&quot;下放&quot;给 S 模式处理。例如，操作系统通常将 <code>ecall</code> 从 U 模式的异常委托给 S 模式，这样系统调用直接进入内核而不经过固件。</p><h3 id="陷阱处理类——记录中断-异常的信息" tabindex="-1">陷阱处理类——记录中断/异常的信息 <a class="header-anchor" href="#陷阱处理类——记录中断-异常的信息" aria-label="Permalink to “陷阱处理类——记录中断/异常的信息”">​</a></h3><table tabindex="0"><thead><tr><th>CSR</th><th>地址</th><th>描述</th></tr></thead><tbody><tr><td><code>mcause</code></td><td>0x342</td><td>陷阱原因（最高位：1=中断，0=异常；低位=原因编号）</td></tr><tr><td><code>mepc</code></td><td>0x341</td><td>陷阱发生时的 PC（mret 从此恢复）</td></tr><tr><td><code>mtval</code></td><td>0x343</td><td>陷阱附加信息（非法指令值、页错误地址等）</td></tr><tr><td><code>mscratch</code></td><td>0x340</td><td>陷阱处理程序暂存寄存器（不参与硬件自动操作）</td></tr></tbody></table><p>当陷阱发生时，硬件自动：</p><ol><li><code>mepc ← PC</code>（保存触发指令的地址）</li><li><code>mcause ← 原因码</code>（标识陷阱类型）</li><li><code>mtval ← 附加信息</code>（对调试有价值的数据）</li><li><code>mstatus.MPIE ← mstatus.MIE; mstatus.MIE ← 0</code>（保存旧中断使能并关中断）</li><li><code>mstatus.MPP ← 当前特权级别</code>（记录从哪个级别来）</li><li><code>PC ← mtvec</code>（跳转到陷阱处理程序）</li></ol><p>看一个具体的 <code>mcause</code> 示例：</p><div class="language-asm"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">csrr    t0, mcause            </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 读陷阱原因</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">srli    t1, t0, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">63</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">             # 提取最高位：1=中断，0=异常</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">andi    t2, t0, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0xFFF</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">          # 提取低 12 位：具体原因编号</span></span></code></pre></div><p>常见原因编号（异常）：0=指令地址不对齐, 2=非法指令, 3=断点, 5=Load 访问错误, 7=Store 访问错误, 8=U 模式 ecall, 9=S 模式 ecall, 11=M 模式 ecall, 12/13/15=页错误。</p><p>常见原因编号（中断）：1=Supervisor 软件中断, 3=M 模式软件中断, 5=Supervisor 定时器中断, 7=M 模式定时器中断, 9=Supervisor 外部中断, 11=M 模式外部中断。</p><h3 id="状态与控制类" tabindex="-1">状态与控制类 <a class="header-anchor" href="#状态与控制类" aria-label="Permalink to “状态与控制类”">​</a></h3><table tabindex="0"><thead><tr><th>CSR</th><th>地址</th><th>描述</th></tr></thead><tbody><tr><td><code>mstatus</code></td><td>0x300</td><td>机器状态寄存器（全局状态控制）</td></tr><tr><td><code>mie</code></td><td>0x304</td><td>中断使能寄存器（位掩码，每位对应一种中断）</td></tr><tr><td><code>mip</code></td><td>0x344</td><td>中断等待寄存器（位掩码，哪些中断已触发但未响应）</td></tr></tbody></table><p><code>mstatus</code> 是 RISC-V 最重要的 CSR 之一——它的字段控制着几乎所有特权行为。关键字段：</p><table tabindex="0"><thead><tr><th>字段</th><th>位</th><th>描述</th></tr></thead><tbody><tr><td>MIE</td><td>[3]</td><td>M 模式全局中断使能（1=开中断）</td></tr><tr><td>SIE</td><td>[1]</td><td>S 模式全局中断使能</td></tr><tr><td>UIE</td><td>[0]</td><td>U 模式全局中断使能</td></tr><tr><td>MPIE</td><td>[7]</td><td>进入陷阱前的 MIE 值（mret 时恢复）</td></tr><tr><td>SPIE</td><td>[5]</td><td>进入陷阱前的 SIE 值</td></tr><tr><td>MPP</td><td>[12:11]</td><td>进入陷阱前的特权级（00=U, 01=S, 11=M）</td></tr><tr><td>FS</td><td>[14:13]</td><td>浮点单元状态（00=Off, 01=Initial, 10=Clean, 11=Dirty）</td></tr><tr><td>XS</td><td>[16:15]</td><td>用户扩展状态</td></tr></tbody></table><p>MPIE/MPP 这三个字段的核心作用是<strong>自动保存和恢复陷阱发生时的 CPU 状态</strong>——硬件在进入陷阱时自动保存，<code>mret</code> 时自动恢复。这比 x86 的手动压栈/弹栈简洁得多。</p><h2 id="csr-使用示例" tabindex="-1">CSR 使用示例 <a class="header-anchor" href="#csr-使用示例" aria-label="Permalink to “CSR 使用示例”">​</a></h2><h3 id="识别当前处理器" tabindex="-1">识别当前处理器 <a class="header-anchor" href="#识别当前处理器" aria-label="Permalink to “识别当前处理器”">​</a></h3><div class="language-asm"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    .</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">section .text</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    .globl _start</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">_start:</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    csrr    a0, mhartid         </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # a0 = hart ID</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    csrr    a1, mvendorid       </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # a1 = 制造商 JEDEC 编码</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    csrr    a2, marchid         </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # a2 = 微架构 ID</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # 将 hart ID 作为参数传给 C 函数</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    call</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    kernel_init</span></span></code></pre></div><h3 id="性能测量框架" tabindex="-1">性能测量框架 <a class="header-anchor" href="#性能测量框架" aria-label="Permalink to “性能测量框架”">​</a></h3><div class="language-asm"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 测量函数执行时间和指令数的宏框架</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.macro MEASURE_BEGIN</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    csrr    s0, cycle           </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # s0 = 起始周期</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    csrr    s1, instret         </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # s1 = 起始指令数</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.endm</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.macro MEASURE_END</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    csrr    s2, cycle           </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # s2 = 结束周期</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    csrr    s3, instret         </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # s3 = 结束指令数</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    sub</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">     s2, s2, s0          </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # s2 = 总周期数</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    sub</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">     s3, s3, s1          </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # s3 = 总指令数</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # s2/s3 = CPI (cycles per instruction)</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.endm</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 使用示例</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">some_function:</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    MEASURE_BEGIN</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # ... 实际代码 ...</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    MEASURE_END</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    ret</span></span></code></pre></div><h3 id="控制全局中断使能" tabindex="-1">控制全局中断使能 <a class="header-anchor" href="#控制全局中断使能" aria-label="Permalink to “控制全局中断使能”">​</a></h3><div class="language-asm"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 禁用 M 模式中断（临界区开始）</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    csrr    t0, mstatus</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    li      t1, ~(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &lt;&lt; </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">3</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)       </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 清除 MIE 位 (bit 3)</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    and</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">     t0, t0, t1</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    csrw    mstatus, t0</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # ... 临界区代码 ...</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 重新启用 M 模式中断（临界区结束）</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    csrr    t0, mstatus</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    ori     t0, t0, (</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &lt;&lt; </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">3</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)    </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 设置 MIE 位</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    csrw    mstatus, t0</span></span></code></pre></div><p>更简洁的方式是使用 <code>csrc</code>/<code>csrs</code> 伪指令（原子操作，推荐）：</p><div class="language-asm"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    csrc    mstatus, (</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &lt;&lt; </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">3</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)   </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 原子清除 MIE 位（关中断）</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # ... 临界区代码 ...</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    csrs    mstatus, (</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &lt;&lt; </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">3</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)   </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 原子设置 MIE 位（开中断）</span></span></code></pre></div><p>原子操作的好处是：读-修改-写是一个不可中断的序列，不会出现&quot;读出旧值后、写回新值前被中断&quot;的竞态。</p><h3 id="设置陷阱向量" tabindex="-1">设置陷阱向量 <a class="header-anchor" href="#设置陷阱向量" aria-label="Permalink to “设置陷阱向量”">​</a></h3><div class="language-asm"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    la      t0, trap_handler    </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 陷阱处理函数的地址</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    csrw    mtvec, t0           </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 设置陷阱向量基址（Direct 模式）</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # mtvec bit[1:0] = 00, 所以直接写地址即可（4 字节对齐）</span></span></code></pre></div><h2 id="本章要点" tabindex="-1">本章要点 <a class="header-anchor" href="#本章要点" aria-label="Permalink to “本章要点”">​</a></h2><ul><li>M/S/U 三级特权，高可访问低；<code>ecall</code> 从低向高切换（U→S→M），<code>mret</code>/<code>sret</code> 从高向低返回——硬件自动在 CSR 中保存/恢复上下文</li><li>CSR 是独立的 12 位地址空间（4096 个槽位），有六条专用指令（<code>csrrw</code>/<code>csrrs</code>/<code>csrrc</code> + 立即数变体 <code>i</code>）及对应的便捷伪指令（<code>csrr</code>/<code>csrw</code>/<code>csrs</code>/<code>csrc</code>）</li><li>计数器 CSR（<code>cycle</code>/<code>time</code>/<code>instret</code>）为性能分析提供硬件级精度，是汇编程序员最常用的 CSR 类别</li><li><code>mstatus</code> 是整个特权架构的控制中枢——MIE/MPIE/MPP 三个字段协同实现了陷阱发生时的自动状态保存和 <code>mret</code> 时的自动恢复</li><li>嵌入式系统可仅实现 M 模式：bare-metal 程序跳过整个 S/U 体系，直接在最高特权级运行——这是 RISC-V 模块化哲学在特权架构中的体现</li></ul>',78))])}]]);export{n as __pageData,r as default};
